## Code Example
```javascript
function propagate(T, edges) {
  const trueSet = new Set(T);
  const queue = [...T];
  const adjacency = new Map();

  for (const [a, b] of edges) {
    if (!adjacency.has(a)) adjacency.set(a, []);
    adjacency.get(a).push(b);
  }

  while (queue.length > 0) {
    const x = queue.shift();
    for (const y of adjacency.get(x) || []) {
      if (!trueSet.has(y)) {
        trueSet.add(y);
        queue.push(y);
      }
    }
  }

  return trueSet;
}
```

