class Propagator {
  constructor(constraints) {
    this.domains = { F1:['T','F','U'], F2:['T','F','U'], F3:['T','F','U'], F4:['T','F','U'], F5:['T','F','U'] };
    this.constraints = constraints;
  }

  propagate(assignment) {
    let changed = true;
    while (changed) {
      changed = false;
      for (const [lhs, rhs, impl] of this.constraints) {
        const a = assignment[lhs] ?? 'U', b = assignment[rhs] ?? 'U';
        const result = impl(a, b);
