## 3-Valued Temporal Propagation with Backtracking

### Approach
1. **Initialize**: Begin with all signals set to U (Unknown)
2. **Forward Propagation**: Apply deterministic implications—specifically, constraint 3 states that if S2(t)=U then S1(t+1)=U
3. **Backtracking Search**: When propagation completes or choices exist, systematically assign values (T/F/U) to unconstrained variables, backtracking on conflict
4. **Constraint Evaluation**: Each constraint employs Kleene three-valued logic—implication yields F only when T→F, otherwise T; F→anything yields T; U→anything yields U

### Corrected Code with Backtracking
```javascript
function solve(signals, maxDepth = 3) {
  const values = ['T', 'F', 'U'];

  function propagate(state) {
    let changed = true;
    while (changed) {
      changed = false;
      for (let t = 0; t < maxDepth - 1; t++) {
        if (state.S2[t] === 'U' && state.S1[t+1] !== 'U') {
          state.S1[t+1] = 'U';
          changed = true;
        }
      }
    }
    return state;
  }

  function solveRecursive(state, depth) {
    if (depth === maxDepth) return state;
    state = propagate(state);

    for (const val of values) {
      const attempt = { ...state, S1: [...state.S1] };
      attempt.S1[depth] = val;
      const result = solveRecursive(attempt, depth + 1);
      if (result && checkConstraints(result)) return result;
    }
    return null;
  }

  function checkConstraints(state) {
    for (let t = 0; t < maxDepth - 1; t++) {
      if (state.S1[t] === 'T' && state.S2[t+1] === 'F') return false;
      if (state.S3[t] === 'F' && state.S4[t+1] !== 'T') return false;
      if (state.S2[t] === 'U' && state.S1[t+1] !== 'U') return false;
    }
    return true;
  }

  return solveRecursive({ S1: Array(maxDepth).fill('U'), S2: Array(maxDepth).fill('U'), S3: Array(maxDepth).fill('U'), S4: Array(maxDepth).fill('U') }, 0);
}
```

