function not(x){ return x==='T'?'F': x==='F'?'T':'U'; }
function and(x,y){ return x===F||y===F?F : x===T&&y===T?T : U; }
function or(x,y){ return x===T||y===T?T : x===F&&y===F?F : U; }
function implies(x,y){ return or(not(x),y); }

// Backtracking propagation
function solve(){
  const vars = {F1:U,F2:U,F3:U,F4:U,F5:U};
  const constraints = [
    () => implies(vars.F1, vars.F2),
    () => implies(vars.F2, vars.F3),
    () => implies(or(vars.F3, vars.F4), vars.F5),
    () => implies(not(vars.F5), or(vars.F1, vars.F2))
  ];

  function backtrack(idx){
    if(idx === 5) return constraints.every(c => c() !== F);
    for(const val of [T,U,F]){
      vars['F'+(idx+1)] = val;
      if(constraints.every(c => c() !== F) && backtrack(idx+1)) return true;
    }
    return false;
  }

  return backtrack(0) ? vars : null;
}
```

